const main = require('../../../lib/jibo-emotion-system');
let Sensor = main.sensing.sensors.Sensor;
let EmotionSystem = main.emotionSystem.EmotionSystem;
const jibo = require('../../../../jibo');


let es = new EmotionSystem();
es.init({
    jibo: jibo
});

// TestSensor1 is intented to be of type Sensor<number>
class TestSensor1 extends Sensor {

    constructor(emitNewDataEvent = false, parent) {
        super('TestSensor1', emitNewDataEvent, parent);
    }

    _dispose() {
        console.log('TestSensor1 disposed');
    }
}

class FirstComeCallback {

    constructor(callback) {
        if (callback) {
            this.callback = callback;
        } else {
            this.callback = (arg = undefined) => {
                console.log(`default callback called with arg ${arg}`);
            };
        }

        this.called = false;
    }

    call(arg) {
        if (!this.called) {
            this.callback(arg);
            this.called = true;
        }
    }
}

let sensor1 = new TestSensor1(null, es);
let sensor2 = new TestSensor1(true, es);

describe('Sensor', () => {
    it('Should have name property', () => {
        expect(sensor1.name).to.equal('TestSensor1');
    });

    it('Should cache last sensor value', () => {
        expect(sensor1.getLastData()).to.not.be.ok;
        sensor1.supplyData(6);
        expect(sensor1.getLastData()).to.equal(6);
    });

    it('Should not emit event on new data if not specified', (done) => {
        let firstCome = new FirstComeCallback(done);
        sensor1.events.newDataEvent.once(() => firstCome.call('error'));
        sensor1.supplyData(6);
        setTimeout(() => firstCome.call(), 200);
    });

    it('Should emit event on new data if specified', (done) => {
        let firstCome = new FirstComeCallback(done);
        sensor2.events.newDataEvent.once(() => firstCome.call());
        sensor2.supplyData(6);
        setTimeout(() => firstCome.call('error'), 200);
    });

});
